import SwiftData

// @Model transforma a classe em modelo persistido:
@Model
class Tarefa {
    var titulo: String
    var concluida: Bool
    var dataCriacao: Date
    var prazo: Date?
    var notas: String?

    // Relacionamento — uma tarefa tem muitas tags:
    @Relationship(deleteRule: .cascade)
    var tags: [Tag] = []

    init(titulo: String, prazo: Date? = nil) {
        self.titulo = titulo
        self.concluida = false
        self.dataCriacao = .now
        self.prazo = prazo
    }
}

@Model
class Tag {
    var nome: String
    var cor: String  // hex string

    @Relationship(inverse: \Tarefa.tags)
    var tarefas: [Tarefa] = []

    init(nome: String, cor: String) {
        self.nome = nome
        self.cor = cor
    }
}

@main
struct MeuAppApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
        }
        // Injeta container com todos os modelos:
        .modelContainer(for: [Tarefa.self, Tag.self])
    }
}

// Container in-memory para Previews e testes:
extension ModelContainer {
    static var preview: ModelContainer {
        let config = ModelConfiguration(isStoredInMemoryOnly: true)
        let container = try! ModelContainer(for: Tarefa.self, configurations: config)

        // Adiciona dados de exemplo:
        let contexto = container.mainContext
        contexto.insert(Tarefa(titulo: "Revisar PR"))
        contexto.insert(Tarefa(titulo: "Escrever testes"))
        return container
    }
}

// Preview com dados:
#Preview {
    ContentView()
        .modelContainer(.preview)
}

struct TarefasView: View {
    // Busca todas as tarefas ordenadas por dataCriacao:
    @Query(sort: \Tarefa.dataCriacao, order: .reverse)
    private var tarefas: [Tarefa]

    // Busca só as pendentes com filtro:
    @Query(
        filter: #Predicate<Tarefa> { !$0.concluida },
        sort: \Tarefa.prazo
    )
    private var pendentes: [Tarefa]

    var body: some View {
        List(tarefas) { tarefa in
            TarefaRow(tarefa: tarefa)
        }
    }
}

// @Query com filtro dinâmico (iOS 17.4+):
struct TarefasFiltradas: View {
    let busca: String

    var query: Query<Tarefa, [Tarefa]> {
        Query(filter: #Predicate<Tarefa> { tarefa in
            busca.isEmpty ? true : tarefa.titulo.contains(busca)
        })
    }

    var body: some View { ... }
}

struct TarefasView: View {
    @Environment(\.modelContext) private var contexto
    @Query private var tarefas: [Tarefa]

    var body: some View {
        List(tarefas) { tarefa in
            TarefaRow(tarefa: tarefa)
                .swipeActions {
                    Button("Deletar", role: .destructive) {
                        contexto.delete(tarefa)  // remove do banco
                    }
                }
        }
        .toolbar {
            Button("Nova") {
                let nova = Tarefa(titulo: "Sem título")
                contexto.insert(nova)  // insere no banco
            }
        }
    }
}

